import { Component, h, Prop } from '@stencil/core';
import { RenderCardContent } from '../../utils/card-content-renderer';
import { HeadingLevel } from '../../models/card.model';

@Component({
  tag: 'wdpr-card-large-content',
  shadow: true,
})
export class WdprCardLargeContent {
  @Prop() primaryHeadline: string;
  @Prop() featureHeadline: string;
  @Prop() headlineLabel: string;
  @Prop() headlineSubtext: string;
  @Prop() body: string;
  @Prop() bullets: string[];
  @Prop() disabled: boolean = false;
  @Prop({ attribute: 'heading-level' }) headingLevel: HeadingLevel = 'h3';

  render() {
    const props = {
      primaryHeadline: this.primaryHeadline,
      featureHeadline: this.featureHeadline,
      headlineLabel: this.headlineLabel,
      headlineSubtext: this.headlineSubtext,
      body: this.body,
      bullets: this.bullets,
      headingLevel: this.headingLevel,
    };

    return (
      <RenderCardContent disabled={this.disabled} variant='large' {...props} />
    );
  }
}